const payload = $('Prepare AI Input').first().json || {};
const mentionMap = payload.mentionMap || {};
const ai = $input.first()?.json || {};

const rawReview = String(
  ai.text || ai.response || ai.output || ai.result || ai.message?.content || ''
);

let review = rawReview
  .replace(/[\x00\x03]/g, ' ')
  .replace(/\r/g, '\n')
  .replace(/\n+/g, '\n')
  .trim();

const reviewMatch = review.match(/(?:^|\n)-?\s*Review\s*:\s*(.+)$/im);
if (reviewMatch?.[1]) {
  review = reviewMatch[1].trim();
} else {
  review = review
    .replace(/(?:^|\n)-?\s*FE passed:[^\n]*/gi, ' ')
    .replace(/(?:^|\n)-?\s*BE passed:[^\n]*/gi, ' ')
    .replace(/(?:^|\n)(?:⚠️\s*)?Warnings?:[\s\S]*/i, ' ')
    .replace(/(?:^|\n)\*WARNINGS\*:[\s\S]*/i, ' ')
    .replace(/```[\s\S]*?```/g, ' ')
    .replace(/\s+/g, ' ')
    .trim()
    .replace(/^[-*•\s]+/, '');
}

review = review.replace(/[\x00\x03`*_]/g, '').replace(/\s+/g, ' ').trim();

if (!review) {
  const remaining = Number(payload.reviewContext?.workingDaysRemaining ?? 0);
  const reviewWarningCount = Number(payload.reviewContext?.warningCount ?? 0);
  const isOverdue = Boolean(payload.reviewContext?.isOverdue);

  if (reviewWarningCount === 0) {
    review = isOverdue
      ? 'Sprint đã quá hạn nhưng chưa có cảnh báo lớn; chốt nốt các việc cuối để hạ cờ an toàn'
      : `Sprint còn ${remaining} ngày, nhịp đang ổn; giữ chắc review và test để về đích gọn gàng`;
  } else {
    review = isOverdue
      ? `Sprint đã quá hạn, còn ${reviewWarningCount} warning; ưu tiên dọn điểm nghẽn lớn nhất ngay`
      : `Sprint còn ${remaining} ngày, có ${reviewWarningCount} warning; ưu tiên xử lý điểm nghẽn lớn nhất trước`;
  }
}

const firstSentence = review.match(/^[^.!?]*[.!?]/);
if (firstSentence?.[0]) review = firstSentence[0].trim();
if (!/[.!?]$/.test(review)) review += '.';

const fe = payload.teams?.FE || { passedTasks: 0, totalTasks: 0, passedPoints: 0, totalPoints: 0 };
const be = payload.teams?.BE || { passedTasks: 0, totalTasks: 0, passedPoints: 0, totalPoints: 0 };

const groups = Array.isArray(payload.warningsGrouped) ? payload.warningsGrouped : [];
const warningGroups = [];

for (const group of groups) {
  const items = Array.isArray(group.items) ? group.items : [];
  if (items.length === 0) continue;

  const firstEmail = items
    .map((item) => String(item.ownerEmail || '').trim().toLowerCase())
    .find(Boolean) || '';

  const mention = firstEmail && mentionMap[firstEmail]
    ? `<users/${mentionMap[firstEmail]}>`
    : String(group.memberTag || '').trim();

  if (!mention) continue;
  warningGroups.push({ mention, items });
}

const warningCount = warningGroups.reduce((sum, group) => sum + group.items.length, 0);
const sprintName = String(payload.sprint?.name || '').trim() || 'Sprint chưa xác định';
const feLine = `FE passed: ${fe.passedTasks}/${fe.totalTasks} tasks — ${fe.passedPoints}/${fe.totalPoints} pts`;
const beLine = `BE passed: ${be.passedTasks}/${be.totalTasks} tasks — ${be.passedPoints}/${be.totalPoints} pts`;
const reviewText = `${review}<br>${
  warningCount > 0
    ? `<font color=\"#fa541c\">🚨 Có ${warningCount} warning cần xử lý ngay.</font>`
    : '<font color=\"#34c759\">🌿 Đỉnh chóp! Không có blocker nào</font>'
}`;

const seed = String(payload.sprint?.id || payload.sprint?.name || 'sprint-healthcheck')
  .toLowerCase()
  .replace(/[^a-z0-9_-]+/g, '-')
  .replace(/^-+|-+$/g, '') || 'sprint-healthcheck';
const uniqueSuffix = `${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 8)}`;
const threadKey = (`sprint-${seed}-${uniqueSuffix}`).slice(0, 120);

const summaryCardPayload = {
  cardsV2: [
    {
      cardId: 'sprint-healthcheck-summary',
      card: {
        sections: [
          {
            widgets: [
              {
                decoratedText: {
                  text: `<b><font color=\"#0F9D58\">🩺 ${sprintName}</font></b>`,
                  wrapText: true,
                },
              },
              {
                decoratedText: {
                  text: `${feLine}<br>${beLine}`,
                  wrapText: true,
                },
              },
              {
                decoratedText: {
                  text: reviewText,
                  wrapText: true,
                },
              },
            ],
          },
        ],
      },
    },
  ],
};

function sanitizeReason(rawReason) {
  return String(rawReason || 'Cần kiểm tra')
    .replace(/\s+/g, ' ')
    .trim()
    .replace(/[.]+$/g, '');
}

const usedVariantIndexesByType = new Map();

function pickRandomNonRepeating(list, typeKey) {
  if (!Array.isArray(list) || list.length === 0) return '';
  const normalizedTypeKey = String(typeKey || 'generic').trim().toLowerCase() || 'generic';

  let usedIndexes = usedVariantIndexesByType.get(normalizedTypeKey);
  if (!(usedIndexes instanceof Set) || usedIndexes.size >= list.length) {
    usedIndexes = new Set();
    usedVariantIndexesByType.set(normalizedTypeKey, usedIndexes);
  }

  const availableIndexes = [];
  for (let index = 0; index < list.length; index += 1) {
    if (!usedIndexes.has(index)) availableIndexes.push(index);
  }

  const selectedIndex = availableIndexes[Math.floor(Math.random() * availableIndexes.length)];
  usedIndexes.add(selectedIndex);
  return list[selectedIndex] || '';
}

function formatWarningReason(item) {
  const warningType = String(item?.type || '').trim().toLowerCase();
  const agingBusinessDays = Number(item?.agingBusinessDays || 0);
  const d = Number.isFinite(agingBusinessDays) ? Math.max(0, agingBusinessDays) : 0;
  const fallbackReason = 'Cần kiểm tra';

  const byType = {
    dev_stale: [
      `Dev ơi task này chậm ${d} ngày rồi nè.`,
      `Quả task này ${d} ngày rồi chưa xong nè.`,
      `Task này nằm hơi lâu rồi đó dev ơi.`,
      `Card này chìm như Titanic luôn rồi nè.`,
      `Task này đang ngủ quên ${d} ngày rồi á.`,
      `Dev ơi kéo card này tiếp đi nè.`,
      `Task này đứng hình ${d} ngày rồi đó.`,
      `Card này bị ngâm hơi kỹ rồi nha dev.`,
      `Task này để lâu quá rồi á dev ơi.`,
      `Dev ơi card này đang chậm nhịp rồi nè.`,
    ],
    wait_qc: [
      `QC ơi card này chờ ${d} ngày rồi nè.`,
      `Quên card này ${d} ngày rồi nè QC ơi.`,
      `Task này đứng đợi QC hơi lâu rồi đó.`,
      `QC ơi ghé card này giúp với nè.`,
      `Card này đang xếp hàng chờ QC đó nha.`,
      `Ready For Test ${d} ngày rồi đó QC ơi.`,
      `Task này đang gọi tên QC đó nè.`,
      `QC ơi kéo nhẹ card này giúp team nha.`,
      `Card này đợi test đến sốt ruột rồi nè.`,
      `QC ơi task này chờ hơi lâu rồi á.`,
    ],
    qc_stale: [
      `QC ơi task này test ${d} ngày rồi nè.`,
      `Card này ở QC hơi lâu rồi đó nha.`,
      `Task này vẫn còn mắc ở QC đó nè.`,
      `QC ơi chốt giúp card này với nè.`,
      `In Test ${d} ngày rồi đó nha QC ơi.`,
      `Task này test hoài chưa chịu xong nè.`,
      `QC ơi card này đang chờ được thả nè.`,
      `Task này còn kẹt QC hơi lâu rồi á.`,
      `QC ơi nhìn tới card này giúp team nha.`,
      `Card này ở khúc test hơi dai rồi đó.`,
    ],
    po_approve: [
      'PO approve cái nhé.',
      'PO ơi chốt card này giúp em nha.',
      'Task này đang chờ PO gật đầu đó ạ.',
      'PO approve giúp để card này được về bờ nha.',
      'Card này còn đứng chờ PO đó nha.',
      'PO ơi duyệt nhẹ một cái giúp team nè.',
      'Task này thiếu mỗi PO approve thôi á.',
      'PO chốt giúp card này cho team thở nha.',
      'Card này còn chờ duyệt đó ạ.',
      'PO ơi approve giúp cái là đẹp luôn nè.',
    ],
    generic: [
      fallbackReason || 'Task này cần được ngó lại nha.',
      `Task này đang chậm nhịp rồi nè.`,
      `Card này cần được kéo tiếp nha.`,
      `Task này đứng hơi lâu rồi đó.`,
      `Card này cần được thương chút nè.`,
      `Task này nhìn hơi rén rồi á.`,
      `Card này đang chờ được cứu nè.`,
      `Task này cần xử lý sớm chút nha.`,
      `Chỗ này nên đẩy tiếp rồi đó nè.`,
      `Task này để lâu không ổn lắm đâu nha.`,
    ],
  };

  const variantPool = byType[warningType] || byType.generic;
  const variant = pickRandomNonRepeating(variantPool, warningType || 'generic');
  return sanitizeReason(variant || fallbackReason || 'Cần kiểm tra');
}

const warningLines = [];
for (let groupIndex = 0; groupIndex < warningGroups.length; groupIndex += 1) {
  const group = warningGroups[groupIndex];
  if (groupIndex > 0) warningLines.push('');
  warningLines.push(`${group.mention}:`);

  for (const item of group.items) {
    const url = String(item.url || '#').trim();
    const key = String(item.key || 'N/A').trim();
    let summary = String(item.summary || 'Không có summary')
      .replace(/\s+/g, ' ')
      .trim()
      .replace(/[.]+$/g, '');
    if (summary.length > 120) summary = `${summary.slice(0, 117).trimEnd()}...`;

    const reason = formatWarningReason(item);

    warningLines.push(` • <${url}|${key}> ${summary} — *${reason}*`);
  }
}

const warningDetailText = warningLines.join('\n');

return [
  {
    json: {
      ...payload,
      review,
      warningCount,
      hasWarnings: warningCount > 0,
      threadKey,
      summaryCardPayload,
      warningDetailText,
      ggChatWebhookUrl:
        payload.config?.ggChatWebhookUrl ||
        $('Config Main').first().json?.config?.ggChatWebhookUrl ||
        '',
    },
  },
];

function buildAggregate() {
 const responseFromJira = $('Get Sprint Issues').first().json || {};
 const sprintPayload = $('Pick Active Sprint').first().json || {};
 const configFromMain = $('Config Main').first().json?.config || sprintPayload.config || {};
 const input = {
 ...responseFromJira,
 config: configFromMain,
 sprint: sprintPayload.sprint || null,
 };

 const config = input.config || {};
 const statusCode = Number(input.statusCode || 200);

 if (statusCode >= 400) {
 return {
 config,
 sprint: input.sprint || null,
 teams: {
 FE: { passedTasks: 0, totalTasks: 0, passedPoints: 0, totalPoints: 0 },
 BE: { passedTasks: 0, totalTasks: 0, passedPoints: 0, totalPoints: 0 },
 UNKNOWN: { passedTasks: 0, totalTasks: 0, passedPoints: 0, totalPoints: 0 }
 },
 warningsGrouped: [],
 reviewContext: {
 warningCount: 0,
 keyRisks: ['Không lấy được dữ liệu issue từ Jira']
 },
 failureReason: `Không lấy được danh sách issue từ Jira (HTTP ${statusCode})`
 };
 }

 const body = input.body && typeof input.body === 'object' ? input.body : input;
 const rawIssues = Array.isArray(body.issues) ? body.issues : [];

 const jiraBaseUrl = String(config.jiraBaseUrl || '').replace(/\/+$/, '');
 const storyPointFieldKey = String(config.storyPointFieldKey || 'customfield_10107').trim();
 const qcsFieldKey = String(config.qcsFieldKey || 'customfield_10201').trim();
 const now = new Date(String(config.nowIso || new Date().toISOString()));
 const sprint = input.sprint || {};
 const sprintStartDate = sprint.startDate ? new Date(sprint.startDate) : null;
 const sprintEndDate = sprint.endDate ? new Date(sprint.endDate) : null;
 const devStaleBusinessDays = Number(config.devStaleBusinessDays || 7);
 const waitQcBusinessDays = Number(config.waitQcBusinessDays || 1);
 const qcStaleBusinessDays = Number(config.qcStaleBusinessDays || 7);
 const nearEndBusinessDays = Number(config.nearEndBusinessDays || 2);
 const tzOffsetMinutes = 7 * 60;

 function parseDate(value) {
 if (!value) return null;
 const date = new Date(value);
 if (Number.isNaN(date.getTime())) return null;
 return date;
 }

 function toDayIndex(date) {
 return Math.floor((date.getTime() + tzOffsetMinutes * 60000) / 86400000);
 }

 function dayOfWeek(dayIndex) {
 return (dayIndex + 4) % 7;
 }

 function isBusinessDay(dayIndex) {
 const dow = dayOfWeek(dayIndex);
 return dow >= 1 && dow <= 5;
 }

 function businessDaysElapsed(startDate, endDate) {
 if (!(startDate instanceof Date) || !(endDate instanceof Date)) return 0;
 const startIndex = toDayIndex(startDate);
 const endIndex = toDayIndex(endDate);
 if (endIndex <= startIndex) return 0;
 let count = 0;
 for (let index = startIndex + 1; index <= endIndex; index += 1) {
 if (isBusinessDay(index)) count += 1;
 }
 return count;
 }

 function businessDaysRemaining(fromDate, toDate) {
 if (!(fromDate instanceof Date) || !(toDate instanceof Date)) return 0;
 const fromIndex = toDayIndex(fromDate);
 const toIndex = toDayIndex(toDate);
 if (toIndex <= fromIndex) return 0;
 let count = 0;
 for (let index = fromIndex + 1; index <= toIndex; index += 1) {
 if (isBusinessDay(index)) count += 1;
 }
 return count;
 }

 function normalizeStatus(rawStatus) {
 const status = String(rawStatus || '').trim();
 const map = {
 open: 'Open',
 'in progress': 'In Progress',
 'ready for test': 'Ready For Test',
 'in test': 'In Test',
 'ready for review': 'Ready For Review',
 'in review': 'In Review',
 'ready for release': 'Ready For Release',
 close: 'Close',
 closed: 'Close'
 };
 return map[status.toLowerCase()] || status;
 }

 function normalizeEmail(value) {
 const email = String(value || '').trim().toLowerCase();
 return email.includes('@') ? email : '';
 }

 function userDisplayName(userValue) {
 if (!userValue) return '';
 if (typeof userValue === 'string') return userValue.trim();
 return String(userValue.displayName || userValue.name || '').trim();
 }

 function userEmail(userValue) {
 if (!userValue) return '';
 if (typeof userValue === 'string') return normalizeEmail(userValue);
 return normalizeEmail(userValue.emailAddress || userValue.email || userValue.mail || '');
 }

 function toTag(name) {
 const cleanName = String(name || '').trim();
 return cleanName ? `@${cleanName}` : '@Unknown';
 }

 function parseNumeric(value) {
 if (typeof value === 'number' && Number.isFinite(value)) return value;
 if (typeof value === 'string') {
 const parsed = Number(value.trim());
 return Number.isFinite(parsed) ? parsed : null;
 }
 if (value && typeof value === 'object') {
 if (typeof value.value === 'number' && Number.isFinite(value.value)) return value.value;
 if (typeof value.value === 'string') {
 const parsed = Number(value.value.trim());
 return Number.isFinite(parsed) ? parsed : null;
 }
 }
 return null;
 }

 function extractStoryPoints(fields) {
 const candidates = [storyPointFieldKey, 'storyPoints', 'Story Points'];
 for (const key of candidates) {
 if (!key) continue;
 if (!Object.prototype.hasOwnProperty.call(fields, key)) continue;
 const parsed = parseNumeric(fields[key]);
 if (parsed !== null) return parsed;
 }
 return 0;
 }

 function normalizePersonList(rawValue) {
 if (!rawValue) return [];
 if (Array.isArray(rawValue)) {
 return rawValue
 .map(item => {
 if (typeof item === 'string') {
 return { name: item.trim(), email: normalizeEmail(item) };
 }
 return {
 name: userDisplayName(item),
 email: userEmail(item)
 };
 })
 .filter(item => item.name || item.email);
 }
 if (typeof rawValue === 'string') {
 return rawValue
 .split(/[;,]/)
 .map(item => item.trim())
 .filter(Boolean)
 .map(item => ({ name: item, email: normalizeEmail(item) }));
 }
 if (typeof rawValue === 'object') {
 const name = userDisplayName(rawValue);
 const email = userEmail(rawValue);
 return name || email ? [{ name, email }] : [];
 }
 return [];
 }

 function extractQcs(fields) {
 const candidates = [qcsFieldKey, 'qcs', 'QCs'];
 for (const key of candidates) {
 if (!key) continue;
 if (!Object.prototype.hasOwnProperty.call(fields, key)) continue;
 const list = normalizePersonList(fields[key]);
 if (list.length > 0) return list;
 }
 return [];
 }

 function sanitizeSummary(summary) {
 const clean = String(summary || '').replace(/\s+/g, ' ').trim();
 return clean || 'Không có summary';
 }

 const allowedIssueTypes = new Set(['Task', 'Bug']);
 const excludedIssueTypes = new Set(['Sub-task', 'Defect']);
 const passedStatuses = new Set(config.passedStatuses || ['Ready For Review', 'In Review', 'Ready For Release', 'Close', 'Closed']);

 const teams = {
 FE: { passedTasks: 0, totalTasks: 0, passedPoints: 0, totalPoints: 0 },
 BE: { passedTasks: 0, totalTasks: 0, passedPoints: 0, totalPoints: 0 },
 UNKNOWN: { passedTasks: 0, totalTasks: 0, passedPoints: 0, totalPoints: 0 }
 };

 const sprintWorkingDaysElapsed = sprintStartDate ? businessDaysElapsed(sprintStartDate, now) : 0;
 const sprintWorkingDaysRemaining = sprintEndDate ? businessDaysRemaining(now, sprintEndDate) : 0;
 const sprintIsOverdue = sprintEndDate ? now > sprintEndDate : false;

 const warningPriority = { po_approve: 1, qc_stale: 2, wait_qc: 3, dev_stale: 4 };
 const issueWarnings = [];

 for (const issue of rawIssues) {
 const fields = issue && typeof issue === 'object' ? (issue.fields || {}) : {};
 const issueType = String(fields.issuetype?.name || '').trim();
 if (excludedIssueTypes.has(issueType)) continue;
 if (!allowedIssueTypes.has(issueType)) continue;

 const key = String(issue.key || '').trim();
 const summary = sanitizeSummary(fields.summary);
 const status = normalizeStatus(fields.status?.name || '');
 const storyPoints = Math.max(0, Number(extractStoryPoints(fields)) || 0);
 const assigneeName = userDisplayName(fields.assignee);
 const assigneeEmail = userEmail(fields.assignee);
 const reporterName = userDisplayName(fields.reporter || fields.creator);
 const reporterEmail = userEmail(fields.reporter || fields.creator);
 const qcs = extractQcs(fields);

 const summaryText = String(summary || '');
 const isFeToken = /\[(APP|FE)\]/i.test(summaryText);
 const isBeToken = /\[(BE|API)\]/i.test(summaryText);
 const isFeAssignee = /app/i.test(assigneeName);

 let team = 'UNKNOWN';
 if (isFeToken || isFeAssignee) team = 'FE';
 else if (isBeToken) team = 'BE';

 const statusFallbackDate = parseDate(fields.statuscategorychangedate) || parseDate(fields.created) || parseDate(fields.updated) || now;
 const histories = Array.isArray(issue?.changelog?.histories) ? issue.changelog.histories : [];
 let statusEnteredDate = null;

 for (const history of histories) {
 const historyDate = parseDate(history?.created);
 if (!historyDate) continue;
 const items = Array.isArray(history?.items) ? history.items : [];
 for (const item of items) {
 if (String(item?.field || '').toLowerCase() !== 'status') continue;
 const toStatus = normalizeStatus(item?.toString || item?.to || '');
 if (toStatus === status && (!statusEnteredDate || historyDate > statusEnteredDate)) {
 statusEnteredDate = historyDate;
 }
 }
 }

 if (!statusEnteredDate) {
 statusEnteredDate = statusFallbackDate;
 }

 const currentStatusAgingBusinessDays = businessDaysElapsed(statusEnteredDate, now);
 const isPassed = passedStatuses.has(status);
 const url = key && jiraBaseUrl ? `${jiraBaseUrl}/browse/${key}` : String(issue?.self || '').trim();

 if (!teams[team]) {
 teams[team] = { passedTasks: 0, totalTasks: 0, passedPoints: 0, totalPoints: 0 };
 }

 teams[team].totalTasks += 1;
 teams[team].totalPoints += storyPoints;
 if (isPassed) {
 teams[team].passedTasks += 1;
 teams[team].passedPoints += storyPoints;
 }


 const assigneeTag = assigneeName ? toTag(assigneeName) : '';
 const reporterTag = reporterName ? toTag(reporterName) : '';
 const qcsTags = qcs.map(person => toTag(person.name || person.email));
 const warningCandidates = [];

if ((status === 'Open' || status === 'In Progress') && currentStatusAgingBusinessDays > devStaleBusinessDays) {
warningCandidates.push({
type: 'dev_stale',
ownerTag: assigneeTag || reporterTag || '@Unknown',
ownerEmail: assigneeEmail || reporterEmail || '',
agingBusinessDays: currentStatusAgingBusinessDays
});
}

if (status === 'Ready For Test' && currentStatusAgingBusinessDays > waitQcBusinessDays) {
warningCandidates.push({
type: 'wait_qc',
ownerTag: qcsTags[0] || reporterTag || '@Unknown',
ownerEmail: qcs[0]?.email || reporterEmail || '',
agingBusinessDays: currentStatusAgingBusinessDays
});
}

if (status === 'In Test' && currentStatusAgingBusinessDays > qcStaleBusinessDays) {
warningCandidates.push({
type: 'qc_stale',
ownerTag: qcsTags[0] || reporterTag || '@Unknown',
ownerEmail: qcs[0]?.email || reporterEmail || '',
agingBusinessDays: currentStatusAgingBusinessDays
});
}

if ((sprintIsOverdue || sprintWorkingDaysRemaining <= nearEndBusinessDays) && (status === 'Ready For Review' || status === 'In Review')) {
warningCandidates.push({
type: 'po_approve',
ownerTag: reporterTag || '@Unknown',
ownerEmail: reporterEmail || '',
agingBusinessDays: currentStatusAgingBusinessDays
});
}

 if (!warningCandidates.length) continue;
 warningCandidates.sort((a, b) => warningPriority[a.type] - warningPriority[b.type]);
 const selected = warningCandidates[0];

issueWarnings.push({
memberTag: selected.ownerTag,
ownerEmail: normalizeEmail(selected.ownerEmail),
key,
url,
summary,
type: selected.type,
team,
status,
agingBusinessDays: Number(selected.agingBusinessDays || currentStatusAgingBusinessDays || 0)
});
 }

 const groupedWarningsMap = new Map();
 for (const warning of issueWarnings) {
 if (!groupedWarningsMap.has(warning.memberTag)) groupedWarningsMap.set(warning.memberTag, []);
groupedWarningsMap.get(warning.memberTag).push({
key: warning.key,
url: warning.url,
summary: warning.summary,
type: warning.type,
agingBusinessDays: warning.agingBusinessDays,
ownerEmail: warning.ownerEmail
});
 }

 const warningsGrouped = Array.from(groupedWarningsMap.entries())
 .map(([memberTag, items]) => ({
 memberTag,
 items: items.sort((a, b) => a.key.localeCompare(b.key))
 }))
 .sort((a, b) => a.memberTag.localeCompare(b.memberTag, 'vi'));

 const fe = teams.FE;
 const be = teams.BE;
 const keyRisks = [];
 if (fe.totalTasks > 0 && fe.passedTasks / fe.totalTasks < 0.6) keyRisks.push('FE còn chậm');
 if (be.totalTasks > 0 && be.passedTasks / be.totalTasks < 0.6) keyRisks.push('BE còn chậm');
 if (issueWarnings.length > 0) keyRisks.push('Tồn tại cảnh báo cần xử lý');
 if (sprintIsOverdue) keyRisks.push('Sprint đã quá hạn');
 if (!sprintIsOverdue && sprintWorkingDaysRemaining <= nearEndBusinessDays) keyRisks.push('Sprint sát hạn');
 if (!keyRisks.length) keyRisks.push('Tiến độ đang ổn định');

 const warningBreakdown = issueWarnings.reduce((acc, warning) => {
 const key = String(warning.type || 'other');
 acc[key] = (acc[key] || 0) + 1;
 return acc;
 }, {});

 const warningMembers = Array.from(new Set(issueWarnings.map(w => String(w.memberTag || '@Unknown')).filter(Boolean))).sort((a, b) => a.localeCompare(b, 'vi'));

 const warningExamples = issueWarnings
 .slice()
 .sort((a, b) => {
 const diff = Number(b.agingBusinessDays || 0) - Number(a.agingBusinessDays || 0);
 if (diff !== 0) return diff;
 return String(a.key || '').localeCompare(String(b.key || ''));
 })
.slice(0, 6)
.map(item => ({
key: item.key,
type: item.type,
team: item.team,
status: item.status,
agingBusinessDays: item.agingBusinessDays,
memberTag: item.memberTag
}));

 return {
 config,
 sprint: {
 id: sprint.id || null,
 name: sprint.name || '',
 startDate: sprint.startDate || '',
 endDate: sprint.endDate || '',
 workingDaysElapsed: sprintWorkingDaysElapsed,
 workingDaysRemaining: sprintWorkingDaysRemaining,
 isOverdue: sprintIsOverdue
 },
 teams: { FE: fe, BE: be, UNKNOWN: teams.UNKNOWN },
 warningsGrouped,
 reviewContext: {
 feRatio: `${fe.passedTasks}/${fe.totalTasks}`,
 beRatio: `${be.passedTasks}/${be.totalTasks}`,
 fePointRatio: `${fe.passedPoints}/${fe.totalPoints}`,
 bePointRatio: `${be.passedPoints}/${be.totalPoints}`,
 warningCount: issueWarnings.length,
 warningBreakdown,
 warningMembers,
 warningExamples,
 keyRisks,
 sprintName: sprint.name || '',
 workingDaysElapsed: sprintWorkingDaysElapsed,
 workingDaysRemaining: sprintWorkingDaysRemaining,
 isOverdue: sprintIsOverdue
 }
 };
}

const aggregate = buildAggregate();

function normalizeEmailForDirectory(value) {
 const email = String(value || '').trim().toLowerCase();
 return email.includes('@') ? email : '';
}

const userDirectory = [];
const mentionMap = {};

for (const item of $input.all()) {
 const row = item?.json && typeof item.json === 'object' ? item.json : {};
 const normalizedRow = {};
 for (const [key, value] of Object.entries(row)) {
 normalizedRow[String(key || '').trim().toLowerCase()] = value;
 }

 const email = normalizeEmailForDirectory(normalizedRow.email);
 const id = String(normalizedRow.id || '').trim();
 const name = String(normalizedRow.name || '').trim();
 if (!email || !id) continue;
 if (mentionMap[email]) continue;
 mentionMap[email] = id;
 userDirectory.push({ email, id, name });
}

const scopedMentionMap = {};
for (const user of userDirectory) {
 scopedMentionMap[user.email] = user.id;
}

return [{
 json: {
 ...aggregate,
 userDirectory,
 mentionMap: scopedMentionMap
 }
}]

