const config = $json.config || $('Config Main').first().json?.config || {};
const boardId = Number(config.boardId || 1041);
const failureReason = String($json.failureReason || '').trim();
const text = failureReason || (`Không tìm thấy active sprint cho board ${boardId}`);

return [{
 json: {
 config,
 sprint: null,
 teams: {
 FE: { passedTasks: 0, totalTasks: 0, passedPoints: 0, totalPoints: 0 },
 BE: { passedTasks: 0, totalTasks: 0, passedPoints: 0, totalPoints: 0 }
 },
 warningsGrouped: [],
 review: '',
 text,
 output: text,
 ggChatWebhookUrl: config.ggChatWebhookUrl || ''
 }
}];

const input = $json || {};
const config = input.config || {};
const boardId = Number(config.boardId || 1041);
const statusCode = Number(input.statusCode || 200);

if (statusCode >= 400) {
 return {
 config,
 hasActiveSprint: false,
 sprint: null,
 failureReason: `Không lấy được active sprint từ Jira (HTTP ${statusCode})`,
 };
}

const body = input.body && typeof input.body === 'object' ? input.body : input;
const values = Array.isArray(body.values) ? body.values : [];
const activeSprints = values
 .filter(item => String(item?.state || '').toLowerCase() === 'active')
 .sort((a, b) => new Date(b?.startDate || 0).getTime() - new Date(a?.startDate || 0).getTime());

const activeSprint = activeSprints[0] || null;

if (!activeSprint) {
 return {
   config,
   hasActiveSprint: false,
   sprint: null,
   failureReason: `Không tìm thấy active sprint cho board ${boardId}`,
   };
}

return {
 config,
 hasActiveSprint: true,
 sprint: {
 id: activeSprint.id,
 name: activeSprint.name || '',
 startDate: activeSprint.startDate || '',
 endDate: activeSprint.endDate || ''
 }
}
